queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?day_spa a :Day_Spa .
    ?day_spa p:name ?name .
    ?day_spa p:Price ?price_f .
    FILTER((STR(?price_f) = "150" || STR(?price_f) = "150.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?wellness_retreat a :Wellness_Retreat .
    ?wellness_retreat p:name ?name .
    ?wellness_retreat p:Price ?price_f .
    FILTER((STR(?price_f) = "150" || STR(?price_f) = "150.0"))
    BIND(?name AS ?o0)
  }
}

